import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Sends a request to the server to open / fetch the Chat Bubble Store.
 * Mirrors the server-side RequestChatBubbleStoreEvent handler.
 */
export class RequestChatBubbleStoreComposer implements IMessageComposer<[]> {
    private _data: [] = [];

    constructor() {
        console.log(
            '[📤] RequestChatBubbleStoreComposer → requesting chat bubble store'
        );
    }

    public getMessageArray(): [] {
        return this._data;
    }

    public dispose(): void {
        this._data = [];
    }
}
